const now = new Date();
const estTime = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
const hour = estTime.getHours();
const day = estTime.getDay();

if (day === 0 || day === 6) {
  return [{ json: { proceed: false, reason: 'Weekend - no calls' } }];
}

if (hour < 8 || hour >= 17) {
  return [{ json: { proceed: false, reason: 'Outside business hours' } }];
}

return [{ json: { proceed: true, currentHour: hour, dayOfWeek: day } }];

const leads = $('Leer Leads Pendientes').all();

let callsToday = 0;
try {
  const stats = $('Leer Stats del Día').all();
  const today = new Date().toISOString().split('T')[0];

  for (const stat of stats) {
    if (stat.json.DATE === today) {
      callsToday = parseInt(stat.json.TOTAL_CALLS) || 0;
      break;
    }
  }
} catch (e) {
  callsToday = 0;
}

if (callsToday >= 25) {
  return [{ json: { proceed: false, reason: 'Already made 10 calls today', callsToday } }];
}

const today = new Date().toISOString().split('T')[0];

const seenPhones = new Set();
const validLeads = leads.filter(lead => {
  const status = String(lead.json.STATUS || '').toUpperCase();
  const attempts = parseInt(lead.json.ATTEMPTS) || 0;
  const phone = String(lead.json.PHONE || '').trim();
  const lastCallDate = String(lead.json.LAST_CALL_DATE || '');

  if (lastCallDate === today) return false;
  if (seenPhones.has(phone)) return false;

  const isValid = (status === 'PENDING') && attempts < 3 && phone.length > 0;

  if (isValid) seenPhones.add(phone);

  return isValid;
});

const leadsToCall = validLeads.slice(0, 1);

if (leadsToCall.length === 0) {
  return [{ json: { proceed: false, reason: 'No valid leads to call', callsToday } }];
}

return leadsToCall.map(lead => ({
  json: {
    ...lead.json,
    callsToday,
    proceed: true
  }
}));

