const agentOutput = $json;
const lead = $('¿Lead Válido?').first().json;

const script = agentOutput.output || agentOutput.text || '';

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/New_York' });

return [{
  json: {
    phone: lead.PHONE,
    leadName: lead.LEAD_NAME || 'there',
    company: lead.COMPANY || '',
    email: lead.EMAIL || '',
    script: script,
    row_number: lead.row_number,
    LEAD_NAME: lead.LEAD_NAME,
    COMPANY: lead.COMPANY,
    PHONE: lead.PHONE,
    EMAIL: lead.EMAIL,
    TITLE: lead.TITLE,
    ATTEMPTS: lead.ATTEMPTS,
    call_date_today: today
  }
}];

const callResult = $json;
const lead = $('Preparar Llamada Bland').first().json;

let callStatus = 'no_answer';
let interestLevel = 'none';
let nextStep = 'callback';
let notes = '';
let painPoints = '';

const fullTranscript = (callResult.concatenated_transcript || '').toLowerCase();
const callLength = callResult.call_length || 0;
const correctedDuration = parseInt(callResult.corrected_duration || '0');
const status = callResult.status || '';
const summary = (callResult.summary || '').toLowerCase();

const durationSeconds = correctedDuration > 0 ? correctedDuration : Math.round(callLength * 60);

const transcripts = callResult.transcripts || [];
const userLines = transcripts
  .filter(t => t.user === 'user')
  .map(t => t.text.toLowerCase())
  .join(' ');

const assistantLines = transcripts
  .filter(t => t.user === 'assistant')
  .map(t => t.text.toLowerCase())
  .join(' ');

// DETECTAR VOICEMAIL PRIMERO
const isVoicemail = fullTranscript.includes('voicemail detection') ||
  fullTranscript.includes('correo de voz') ||
  fullTranscript.includes('contestador') ||
  fullTranscript.includes('leave a message') ||
  fullTranscript.includes('deje su mensaje') ||
  fullTranscript.includes('ssn_redacted') ||
  callResult.voicemail_detected === true ||
  (callResult.answered_by === 'voicemail') ||
  assistantLines.includes('call ended due to voicemail');

if (status === 'completed' && isVoicemail) {
  callStatus = 'voicemail';
  notes = 'Voicemail detected - call ended automatically';
  nextStep = 'callback';
  interestLevel = 'none';
} else if (status === 'completed' && userLines.length > 5 && !isVoicemail && durationSeconds > 15) {
  callStatus = 'answered';

  // Detectar pain points
  if (userLines.includes('scale') || userLines.includes('scaling') || userLines.includes('grow')) painPoints += 'Scaling team; ';
  if (userLines.includes('cost') || userLines.includes('budget') || userLines.includes('expensive') || userLines.includes('reduce cost')) painPoints += 'Cost concerns; ';
  if (userLines.includes('security') || userLines.includes('cyber')) painPoints += 'Cybersecurity needs; ';
  if (userLines.includes('cloud') || userLines.includes('aws') || userLines.includes('azure')) painPoints += 'Cloud needs; ';
  if (userLines.includes('ai ') || userLines.includes('ai,') || userLines.includes('artificial') || userLines.includes('machine learning')) painPoints += 'AI/ML needs; ';

  // USAR SUMMARY COMO FUENTE PRINCIPAL
  const summaryHasMeeting = summary.includes('scheduled') || summary.includes('follow-up call') || summary.includes('calendar invite') || summary.includes('meeting is set');
  const summaryHasInterest = summary.includes('expressed interest') || summary.includes('showed interest') || summary.includes('open to');
  const summaryHasNoInterest = (summary.includes('no interest') || summary.includes('not interested') || summary.includes('declined')) && !summaryHasMeeting;
  const summaryHasEmailFollowup = summary.includes('send info') || summary.includes('send email') || summary.includes('email follow') || summary.includes('send over') || summary.includes('information sent') || summary.includes('get that information');
  const summaryHasNoAction = summary.includes('no further action') && !summaryHasMeeting && !summaryHasEmailFollowup;

  // Detectar de userLines
  const userAcceptedMeeting = userLines.includes('of course') || userLines.includes('sounds good') || userLines.includes('let\'s do it');
  const userMentionedSchedule = userLines.includes('wednesday') || userLines.includes('monday') || userLines.includes('tuesday') || userLines.includes('thursday') || userLines.includes('friday') || userLines.includes('next week') || userLines.includes('tomorrow') || userLines.includes('10:00') || userLines.includes('10 am') || userLines.includes('11:00') || userLines.includes('11 am') || userLines.includes('morning') || userLines.includes('afternoon');
  const userWantsEmail = userLines.includes('send me') || userLines.includes('email') || userLines.includes('send info') || userLines.includes('information') || userLines.includes('send over');

  const strongRejection = userLines.includes('not interested') || 
    userLines.includes('no thank') || 
    userLines.includes("don't call") || 
    userLines.includes('remove me') || 
    userLines.includes('stop calling') ||
    userLines.includes('don\'t have any need') ||
    userLines.includes('don\'t have any necessity') ||
    userLines.includes('we don\'t need') ||
    userLines.includes('not looking for');

  // LÓGICA DE DECISIÓN
  if (summaryHasMeeting || (userAcceptedMeeting && userMentionedSchedule)) {
    interestLevel = 'high';
    nextStep = 'meeting_scheduled';
  } else if (summaryHasEmailFollowup || userWantsEmail) {
    interestLevel = 'medium';
    nextStep = 'send_email';
  } else if (strongRejection || summaryHasNoAction || summaryHasNoInterest) {
    interestLevel = 'none';
    nextStep = 'not_interested';
  } else if (summaryHasInterest) {
    interestLevel = 'high';
    nextStep = 'meeting_scheduled';
  } else {
    interestLevel = 'low';
    nextStep = 'callback';
  }

  notes = callResult.summary || 'Call completed';
} else if (status === 'completed') {
  callStatus = 'no_answer';
  notes = 'Call too short - no meaningful interaction';
} else {
  callStatus = (status === 'busy') ? 'busy' : 'no_answer';
  notes = (status === 'busy') ? 'Line busy' : 'No answer - ' + status;
}

// DETERMINAR STATUS DEL LEAD
let newStatus = 'PENDING';
const currentAttempts = (parseInt(lead.ATTEMPTS) || 0) + 1;

if (nextStep === 'meeting_scheduled') newStatus = 'SCHEDULED';
else if (nextStep === 'not_interested') newStatus = 'NOT_INTERESTED';
else if (nextStep === 'send_email') newStatus = 'FOLLOW_UP';
else if (callStatus === 'answered' && interestLevel === 'low') newStatus = 'CONTACTED';
else if (callStatus === 'voicemail' || callStatus === 'no_answer') newStatus = 'PENDING';
else if (currentAttempts >= 3 && callStatus !== 'answered') newStatus = 'NO_ANSWER';

const now = new Date();
const estOpts = { timeZone: 'America/New_York' };
const dateStr = now.toLocaleDateString('en-CA', estOpts);
const timeStr = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true, ...estOpts });

let calendlyLink = '';
if (nextStep === 'meeting_scheduled' && lead.EMAIL) {
  calendlyLink = 'https://calendly.com/nataly-riano-msitechnologiesinc/30min?name=' + encodeURIComponent(lead.LEAD_NAME || '') + '&email=' + encodeURIComponent(lead.EMAIL) + '&a1=' + encodeURIComponent(lead.COMPANY || '');
}

return [{
  json: {
    row_number: lead.row_number,
    LEAD_NAME: lead.LEAD_NAME,
    COMPANY: lead.COMPANY,
    PHONE: lead.PHONE,
    EMAIL: lead.EMAIL,
    call_id: callResult.call_id || '',
    call_status: callStatus,
    interest_level: interestLevel,
    pain_points: painPoints.trim(),
    next_step: nextStep,
    notes: notes,
    transcript: callResult.concatenated_transcript || '',
    recording_url: callResult.recording_url || '',
    duration: durationSeconds,
    new_status: newStatus,
    new_attempts: currentAttempts,
    call_date: dateStr,
    call_time: timeStr,
    calendly_link: calendlyLink,
    summary: callResult.summary || notes
  }
}];

const resultado = $('Analizar Resultado').first().json;
const today = resultado.call_date;
const callStatus = resultado.call_status;
const interestLevel = resultado.interest_level;
const nextStep = resultado.next_step;

// Leer stats existentes del día
let existingStats = null;
try {
  const allStats = $('Leer Stats del Día').all();
  for (const stat of allStats) {
    if (stat.json.DATE === today) {
      existingStats = stat.json;
      break;
    }
  }
} catch (e) {
  existingStats = null;
}

let stats;
if (existingStats) {
  stats = {
    DATE: today,
    TOTAL_CALLS: (parseInt(existingStats.TOTAL_CALLS) || 0) + 1,
    ANSWERED: (parseInt(existingStats.ANSWERED) || 0) + (callStatus === 'answered' ? 1 : 0),
    VOICEMAIL: (parseInt(existingStats.VOICEMAIL) || 0) + (callStatus === 'voicemail' ? 1 : 0),
    NO_ANSWER: (parseInt(existingStats.NO_ANSWER) || 0) + (callStatus === 'no_answer' ? 1 : 0),
    MEETINGS_SCHEDULED: (parseInt(existingStats.MEETINGS_SCHEDULED) || 0) + (nextStep === 'meeting_scheduled' ? 1 : 0),
    INTERESTED: (parseInt(existingStats.INTERESTED) || 0) + (interestLevel === 'high' || interestLevel === 'medium' ? 1 : 0),
    NOT_INTERESTED: (parseInt(existingStats.NOT_INTERESTED) || 0) + (nextStep === 'not_interested' ? 1 : 0),
    isUpdate: true
  };
} else {
  stats = {
    DATE: today,
    TOTAL_CALLS: 1,
    ANSWERED: callStatus === 'answered' ? 1 : 0,
    VOICEMAIL: callStatus === 'voicemail' ? 1 : 0,
    NO_ANSWER: callStatus === 'no_answer' ? 1 : 0,
    MEETINGS_SCHEDULED: nextStep === 'meeting_scheduled' ? 1 : 0,
    INTERESTED: (interestLevel === 'high' || interestLevel === 'medium') ? 1 : 0,
    NOT_INTERESTED: nextStep === 'not_interested' ? 1 : 0,
    isUpdate: false
  };
}

return [{ json: stats }];

const lead = $('Preparar Llamada Bland').first().json;

const body = {
  phone_number: lead.phone,
  task: lead.script,
  voice: "4e65cda2-cf46-4907-84ba-3ca96c48f549",
  first_sentence: "Hi, this is Laura from MSI Technologies. Am I speaking with " + lead.leadName + "?",
  wait_for_greeting: true,
  noise_cancellation: true,
  record: true,
  max_duration: 3,
  language: "en",
  model: "enhanced",
  interruption_threshold: 200,
  temperature: 0.7,
  answering_machine_detection: true,
  voicemail_action: "hangup",
  metadata: {
    lead_name: lead.LEAD_NAME,
    company: lead.COMPANY,
    email: lead.EMAIL,
    row_number: String(lead.row_number)
  }
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.bland.ai/v1/calls',
  headers: {
    'Content-Type': 'application/json',
    'authorization': 'org_0c04c275db89a23a555a1f653c646c46b6239aef0b0fb08eebcbb12b5da31fcd49bc1e14aaa0d22a68ca69'
  },
  body: body
});

return [{ json: { ...response, ...lead } }];
